const t=[{title:"பசுமை\\nபண்ணையிலிருந்து\\nஉங்கள் மேசைக்கு",subtitle:"இலங்கையின் நம்பகமான கோழி வழங்குநர்.",button:"தயாரிப்புகளை பார்க்கவும்"},{title:"நம்பகமான\\nதரம்\\nஒவ்வொரு நாளும்",subtitle:"ஹலால் சான்றிதழ், ஆன்டிபயாட்டிக் இல்லா செயல்முறை, குளிர்சங்கிலி பாதுகாப்பு.",button:"விநியோகஸ்தராக இணையுங்கள்"},{title:"ஒவ்வொரு\\nஉயிரையும்\\nகவனிக்கும் பராமரிப்பு",subtitle:"மனிதாபிமான வளர்ப்பு முறைகள் மற்றும் நெருக்கமான கால்நடை மருத்துவ மேற்பார்வை.",button:"எங்கள் செயல்முறை"},{title:"நவீன\\nஅளவுரு\\nவசதிகள்",subtitle:"உயர் உயிர் பாதுகாப்பு தரங்களை உறுதி செய்யும் நவீன உட்கட்டமைப்பு.",button:"மேலும் அறிய"},{title:"குளிர்சங்கிலி\\nபுதிய\\nவிநியோகம்",subtitle:"கடுமையான வெப்பநிலை கட்டுப்பாட்டுடன் கையாளப்பட்டு கடத்தப்படுகிறது.",button:"தயாரிப்புகளை பார்க்கவும்"},{title:"முழுமையான\\nகண்காணிப்பு\\nநீங்கள் நம்பலாம்",subtitle:"ஹாட்சரியிலிருந்து விற்பனை வரை ஒரே தரமான செயல்முறை.",button:"மேலும் அறிய"},{title:"சான்றளிக்கப்பட்ட\\nபாதுகாப்பு\\nதரநிலைகள்",subtitle:"ஒழுங்குமுறை, ஆய்வுகள் மற்றும் தர உறுதிப்பாடு அடிப்படையில் உருவாக்கப்பட்டது.",button:"தரமும் பாதுகாப்பும்"}],n={heroSlides:t};export{n as default,t as heroSlides};
